import { useEffect, useState } from "react";

export default function DuckHunt() {
  const [score, setScore] = useState(0);
  const [x, setX] = useState(0);
  const [y, setY] = useState(0);

  function spawnDuck() {
    setX(Math.random() * 350);
    setY(Math.random() * 250);
  }

  function killDuck() {
    setScore(score + 1);
    spawnDuck();
  }

  useEffect(() => {
    spawnDuck();

    const id = setInterval(spawnDuck, 1000);
    return () => clearInterval(id);
  }, []);

  return (
    <div className="container">
      <h1>🔫 Duck Hunt</h1>

      <h2>Score: {score}</h2>

      <div
        style={{
          position: "relative",
          width: 400,
          height: 300,
          cursor: "crosshair",
        }}
      >
        <div
          style={{
            position: "absolute",
            left: x,
            top: y,
            fontSize: "2.5rem",
            userSelect: "none",
          }}
          onClick={killDuck}
        >
          🦆
        </div>
      </div>
    </div>
  );
}
